import React, { useState, useEffect } from 'react';
import { useAuth0 } from '@auth0/auth0-react';
import emailjs from '@emailjs/browser';

const styles = `
  @import url('https://fonts.googleapis.com/css2?family=Syne:wght@400;700;800&family=DM+Sans:wght@300;400;500&display=swap');
  * { margin:0; padding:0; box-sizing:border-box; }
  
  :root {
    --bg:#060612; --card:#11112a; --card2:#16163a;
    --border:rgba(255,255,255,0.07);
    --accent:#6c63ff; --accent2:#00d4ff; --accent3:#ff6b9d;
    --text:#f0f0ff; --muted:#7b7b9d; --success:#00e5a0;
    --warn:#f0a500; --danger:#ff4d4d;
  }

  /* SCROLL REPAIR */
  html, body, #root { 
    height: 100vh; 
    width: 100vw; 
    overflow: hidden; 
    background: var(--bg);
    font-family: 'DM Sans', sans-serif;
    color: var(--text);
  }

  .bg-canvas{position:fixed;inset:0;z-index:0;overflow:hidden;pointer-events:none;}
  .orb{position:absolute;border-radius:50%;filter:blur(80px);opacity:0.2;}
  .orb-1{width:600px;height:600px;background:var(--accent);top:-200px;left:-100px;}
  
  .dash-wrap {
    position: relative;
    z-index: 1;
    height: 100vh;
    display: flex;
    flex-direction: column;
  }

  .dash-nav {
    height: 65px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0 32px;
    border-bottom: 1px solid var(--border);
    background: rgba(6,6,18,0.8);
    backdrop-filter: blur(12px);
    flex-shrink: 0;
  }

  .dash-body {
    display: grid;
    grid-template-columns: 280px 1fr 400px;
    flex: 1;
    height: calc(100vh - 65px);
    overflow: hidden;
  }

  /* PANEL SCROLLING - FORCED */
  .sidebar, .main-panel, .detail-panel {
    height: 100%;
    overflow-y: auto !important;
    padding: 24px;
    border-right: 1px solid var(--border);
  }

  .detail-panel { border-right: none; }

  /* UI COMPONENTS */
  .dash-logo{font-family:'Syne',sans-serif;font-size:20px;font-weight:800;color:var(--accent);}
  .sidebar-title{font-size:11px;color:var(--muted);letter-spacing:0.1em;text-transform:uppercase;margin-bottom:15px;}
  .perm-item{display:flex;align-items:center;justify-content:space-between;padding:12px;border-radius:10px;margin-bottom:8px;background:rgba(255,255,255,0.02);border:1px solid var(--border);}
  
  .email-card{background:var(--card);border:1px solid var(--border);border-radius:14px;padding:18px;margin-bottom:12px;cursor:pointer;transition:0.2s;}
  .email-card:hover{border-color:var(--accent);background:var(--card2);}
  .email-card.active{border-left:4px solid var(--accent); background:var(--card2);}
  
  .detail-body{font-size:15px;line-height:1.7;background:rgba(255,255,255,0.02);border-radius:12px;padding:20px;margin-bottom:20px;white-space:pre-line;}
  .compose-textarea{width:100%;padding:15px;background:rgba(0,0,0,0.2);border:1px solid var(--border);border-radius:10px;color:white;min-height:150px;outline:none;font-family:inherit;}
  .send-btn{width:100%;padding:14px;background:var(--accent);border:none;border-radius:10px;color:white;font-weight:700;cursor:pointer;margin-top:10px;}
  
  /* Scrollbar styling */
  ::-webkit-scrollbar { width: 6px; }
  ::-webkit-scrollbar-thumb { background: var(--border); border-radius: 10px; }
`;

const MOCK_EMAILS = Array.from({ length: 12 }, (_, i) => ({
  id: i + 1,
  name: i % 2 === 0 ? "Sarah Johnson" : "Rahul Mehta",
  subject: `Project Update ${i + 1}`,
  body: `This is the body for email ${i + 1}. We are testing the scrolling system to ensure the dashboard doesn't freeze when the list gets long.`,
  time: "10:42 AM",
  unread: i < 3
}));

function Dashboard() {
  const { user, logout } = useAuth0();
  const [selected, setSelected] = useState(MOCK_EMAILS[0]);
  const [composeBody, setComposeBody] = useState("");
  const [sending, setSending] = useState(false);

  const handleSend = async () => {
    if (!composeBody) return;
    setSending(true);
    try {
      await emailjs.send(
        process.env.REACT_APP_EMAILJS_SERVICE_ID,
        process.env.REACT_APP_EMAILJS_TEMPLATE_ID,
        { message: composeBody, to_name: selected.name, from_name: user.name },
        process.env.REACT_APP_EMAILJS_PUBLIC_KEY
      );
      alert("Sent!");
      setComposeBody("");
    } catch (err) {
      console.error(err);
    }
    setSending(false);
  };

  return (
    <div className="dash-wrap">
      <nav className="dash-nav">
        <div className="dash-logo">🛡️ GUARDY AI</div>
        <div style={{display:'flex', alignItems:'center', gap:15}}>
          <span style={{fontSize:12, color:'var(--muted)'}}>{user?.email}</span>
          <button onClick={() => logout()} style={{background:'none', border:'1px solid var(--border)', color:'white', padding:'5px 10px', borderRadius:5, cursor:'pointer'}}>Logout</button>
        </div>
      </nav>

      <div className="dash-body">
        {/* Sidebar */}
        <div className="sidebar">
          <h3 className="sidebar-title">Security Tokens</h3>
          <div className="perm-item"><span>Read Access</span><input type="checkbox" defaultChecked /></div>
          <div className="perm-item"><span>AI Summary</span><input type="checkbox" defaultChecked /></div>
          <div className="perm-item"><span>Auto Reply</span><input type="checkbox" /></div>
        </div>

        {/* Inbox List - This now scrolls! */}
        <div className="main-panel">
          <h2 style={{fontFamily:'Syne', marginBottom:20}}>Inbox</h2>
          {MOCK_EMAILS.map(e => (
            <div key={e.id} className={`email-card ${selected.id === e.id ? 'active' : ''}`} onClick={() => setSelected(e)}>
              <div style={{display:'flex', justifyContent:'space-between', marginBottom:5}}>
                <strong style={{fontSize:14}}>{e.name}</strong>
                <span style={{fontSize:11, color:'var(--muted)'}}>{e.time}</span>
              </div>
              <div style={{fontSize:14, fontWeight:600}}>{e.subject}</div>
            </div>
          ))}
        </div>

        {/* Email Detail - This also scrolls! */}
        <div className="detail-panel">
          <h2 style={{fontFamily:'Syne', marginBottom:5}}>{selected.subject}</h2>
          <p style={{fontSize:12, color:'var(--muted)', marginBottom:20}}>From: {selected.name}</p>
          <div className="detail-body">{selected.body}</div>
          
          <textarea 
            className="compose-textarea" 
            placeholder="Write your secure reply..." 
            value={composeBody}
            onChange={(e) => setComposeBody(e.target.value)}
          />
          <button className="send-btn" onClick={handleSend} disabled={sending}>
            {sending ? "Encrypting & Sending..." : "Send Secure Reply"}
          </button>
        </div>
      </div>
    </div>
  );
}

function App() {
  const { isAuthenticated, isLoading, loginWithRedirect } = useAuth0();

  if (isLoading) return <div style={{color:'white', padding:40}}>Loading...</div>;

  return (
    <>
      <style>{styles}</style>
      <div className="bg-canvas"><div className="orb orb-1"/></div>
      
      {!isAuthenticated ? (
        <div style={{height:'100vh', display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', position:'relative', zIndex:10}}>
          <h1 style={{fontFamily:'Syne', fontSize:80, fontWeight:800}}>Guardy AI</h1>
          <button className="send-btn" style={{width:200}} onClick={() => loginWithRedirect()}>Login</button>
        </div>
      ) : (
        <Dashboard />
      )}
    </>
  );
}

export default App;
